Code.Terraform:
```hcl
# 仅在 AWS Organization 内共享 Service Catalog 产品组合
resource "aws_servicecatalog_portfolio_share" "<example_resource_name>" {
  portfolio_id = "<example_resource_id>"

  organization_node {           # 关键：在 AWS Organizations 内共享
    type  = "ORGANIZATION"     # 与整个组织共享该投资组合
    value = "<example_resource_id>"  # 例如，o-xxxxxxxxxx
  }
}
```
